// src/components/speed-dial-context.tsx
import * as React from "react";
var SpeedDialContext = React.createContext(
  null
);
function useSpeedDial() {
  const context = React.useContext(SpeedDialContext);
  if (!context) {
    throw new Error(
      "SpeedDial compound components must be used within <SpeedDial>."
    );
  }
  return context;
}

export {
  SpeedDialContext,
  useSpeedDial
};
